import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';



const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [displayText, setDisplayText] = useState('');
  const [isTyping, setIsTyping] = useState(true);
  const [showDots, setShowDots] = useState(false);


  const fullText = 'Nautilus Automação';
  const typingSpeed = 150;
  const pauseTime = 10000;





  useEffect(() => {
    let timeoutId;
    let currentIndex = 0;

    const typeText = () => {
      if (currentIndex <= fullText.length) {
        setDisplayText(fullText.slice(0, currentIndex));
        currentIndex++;
        timeoutId = setTimeout(typeText, typingSpeed);
      } else {
        setIsTyping(false);
        setShowDots(true);
        timeoutId = setTimeout(() => {
          setShowDots(false);
          setIsTyping(true);
          setDisplayText('');
          currentIndex = 0;
          typeText();
        }, pauseTime);
      }
    };

    typeText();

    return () => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
    };
  }, []);



  // Removido - não precisamos mais da animação de fundo

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Limpar erro quando o usuário começar a digitar
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Validação básica
    if (!formData.email || !formData.password) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    // Validação simples de email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    try {
      const result = await login(formData.email, formData.password);

      if (result.success) {
        toast.success('Login realizado com sucesso!');
      } else {
        setError(result.message || 'Erro ao fazer login');
        toast.error(result.message || 'Erro ao fazer login');
      }
    } catch (error) {
      console.error('Erro no login:', error);
      setError('Erro ao fazer login. Tente novamente.');
      toast.error('Erro ao fazer login');
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        background: '#000000', // Fundo preto
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2
      }}
    >
      {/* CSS para animações */}
      <style>
        {`
          @keyframes blink {
            0%, 50% { opacity: 1; }
            51%, 100% { opacity: 0; }
          }
          @keyframes blinkDots {
            0%, 33% { opacity: 1; }
            34%, 66% { opacity: 0.5; }
            67%, 100% { opacity: 0; }
          }
          @keyframes shimmer {
            0% {
              background-position: -200% 0;
            }
            100% {
              background-position: 200% 0;
            }
          }
          @keyframes float {
            0%, 100% { transform: translateY(0px) rotate(0deg); }
            50% { transform: translateY(-10px) rotate(180deg); }
          }
          @keyframes glow {
            0%, 100% { text-shadow: 0 0 5px currentColor; }
            50% { text-shadow: 0 0 20px currentColor, 0 0 30px currentColor; }
          }
        `}
      </style>




      {/* Cartão de Crédito */}
      <Box
        sx={{
          width: '100%',
          maxWidth: 500,
          height: 400,
          background: 'linear-gradient(135deg, rgba(192, 192, 192, 0.1) 0%, rgba(169, 169, 169, 0.05) 100%)',
          borderRadius: '20px',
          border: '1px solid rgba(192, 192, 192, 0.3)',
          backdropFilter: 'blur(20px)',
          position: 'relative',
          overflow: 'hidden',
          boxShadow: '0 8px 32px rgba(0, 0, 0, 0.3), inset 0 1px 0 rgba(255, 255, 255, 0.1)',
          zIndex: 2, // Garante que o cartão fique acima dos símbolos
          '&::before': {
            content: '""',
            position: 'absolute',
            top: 0,
            left: '-100%',
            width: '100%',
            height: '100%',
            background: 'linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.1), transparent)',
            animation: 'shimmer 3s infinite'
          }
        }}
      >
        {/* Chip do cartão removido */}

        {/* Logo/Marca removido */}

        {/* Área do formulário */}
        <Box
          sx={{
            position: 'absolute',
            bottom: 0,
            left: 0,
            right: 0,
            padding: 4,
            background: 'rgba(0, 0, 0, 0.2)',
            borderTop: '1px solid rgba(192, 192, 192, 0.2)',
            minHeight: '300px'
          }}
        >
          <Box component="form" onSubmit={handleSubmit}>
            {/* Título do cartão */}
            <Box sx={{ textAlign: 'center', mb: 2 }}>
              <Typography
                variant="h6"
                component="h1"
                sx={{
                  fontWeight: 'bold',
                  color: '#C0C0C0',
                  mb: 3,
                  fontSize: '1.5rem',
                  textTransform: 'uppercase',
                  letterSpacing: '1px'
                }}
              >
                Nautilus Automação
              </Typography>
            </Box>
              {error && (
                <Alert 
                  severity="error" 
                  sx={{ 
                    mb: 3,
                    backgroundColor: 'rgba(211, 47, 47, 0.1)',
                    color: '#ff6b6b',
                    border: '1px solid rgba(211, 47, 47, 0.3)',
                    '& .MuiAlert-icon': {
                      color: '#ff6b6b'
                    }
                  }}
                >
                  {error}
                </Alert>
              )}

              <TextField
                fullWidth
                name="email"
                label="USUÁRIO"
                type="email"
                value={formData.email}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="email"
                autoFocus
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Email sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: 'rgba(192, 192, 192, 0.05)',
                    border: '1px solid rgba(192, 192, 192, 0.3)',
                    borderRadius: '8px',
                    color: '#C0C0C0',
                    '& fieldset': {
                      border: 'none'
                    },
                    '&:hover': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid rgba(192, 192, 192, 0.5)'
                    },
                    '&.Mui-focused': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid #C0C0C0'
                    }
                  },
                  '& .MuiInputLabel-root': {
                    color: '#A9A9A9',
                    fontSize: '1rem',
                    fontWeight: 'bold',
                    letterSpacing: '1px'
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#C0C0C0'
                  }
                }}
              />

              <TextField
                fullWidth
                name="password"
                label="SENHA"
                type={showPassword ? 'text' : 'password'}
                value={formData.password}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="current-password"
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Lock sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={togglePasswordVisibility}
                        edge="end"
                        aria-label="toggle password visibility"
                        sx={{ color: '#C0C0C0' }}
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: 'rgba(192, 192, 192, 0.05)',
                    border: '1px solid rgba(192, 192, 192, 0.3)',
                    borderRadius: '8px',
                    color: '#C0C0C0',
                    '& fieldset': {
                      border: 'none'
                    },
                    '&:hover': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid rgba(192, 192, 192, 0.5)'
                    },
                    '&.Mui-focused': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid #C0C0C0'
                    }
                  },
                  '& .MuiInputLabel-root': {
                    color: '#A9A9A9',
                    fontSize: '1rem',
                    fontWeight: 'bold',
                    letterSpacing: '1px'
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#C0C0C0'
                  }
                }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                disabled={loading}
                sx={{
                  mt: 2,
                  mb: 1,
                  py: 1,
                  fontSize: '1.125rem',
                  fontWeight: 'bold',
                  textTransform: 'uppercase',
                  letterSpacing: '1px',
                  background: 'linear-gradient(135deg, rgba(192, 192, 192, 0.2), rgba(169, 169, 169, 0.1))',
                  color: '#C0C0C0',
                  border: '1px solid rgba(192, 192, 192, 0.3)',
                  borderRadius: '8px',
                  backdropFilter: 'blur(10px)',
                  '&:hover': {
                    background: 'linear-gradient(135deg, rgba(192, 192, 192, 0.3), rgba(169, 169, 169, 0.2))',
                    border: '1px solid rgba(192, 192, 192, 0.5)',
                  },
                  '&:disabled': {
                    background: 'rgba(192, 192, 192, 0.05)',
                    color: 'rgba(192, 192, 192, 0.3)',
                  },
                }}
              >
                {loading ? (
                  <CircularProgress size={20} sx={{ color: '#C0C0C0' }} />
                ) : (
                  'ENTRAR'
                )}
              </Button>

              {/* Link para registro */}
              <Box sx={{ textAlign: 'center', mt: 1 }}>
                <Typography 
                  variant="body2" 
                  sx={{ 
                    color: '#A9A9A9',
                    fontSize: '1rem'
                  }}
                >
                  Não tem conta?{' '}
                  <Link
                    component={RouterLink}
                    to="/register"
                    sx={{
                      color: '#C0C0C0',
                      textDecoration: 'none',
                      fontWeight: 'bold',
                      fontSize: '1rem',
                      '&:hover': {
                        textDecoration: 'underline',
                        color: '#DCDCDC'
                      },
                    }}
                  >
                    REGISTRE-SE
                  </Link>
                </Typography>
              </Box>
            </Box>
          </Box>
        </Box>
      </Box>
  );
};

export default Login;
